def _normalizza_argomenti(sequenza, output=None):
    """
    Normalizza gli argomenti della dichiarazione

    Gli argomenti di normalizzazione possono contenere Dichiarazioni, tuple o singole
    interfacce.

    Qualsiasi cosa diversa da interfacce individuali o specifiche di implementazione verrà espansa.
    """
    if output is None:
        output = []

    for item in sequenza:
        if isinstance(item, (list, tuple)):
            _normalizza_argomenti(item, output)
        elif hasattr(item, 'interfacce'):
            _normalizza_argomenti(item.interfacce, output)
        else:
            output.append(item)

    return output

def _aggiorna_contesto(self, contesto):
    # Dictionary mapping coordinate names to x,y,z labels
    coord_map = {0: 'x', 1: 'y', 2: 'z'}

    # Initialize error subcontext if it doesn't exist
    if 'error' not in contesto:
        contesto['error'] = {}

    # Iterate through fields looking for error fields
    for i, field in enumerate(self.fields):
        # Check for error fields (containing 'error' in name)
        if 'error' in field.lower():
            # Extract coordinate index from field name
            for coord_idx, coord_name in coord_map.items():
                if f'error_{coord_name}' in field.lower():
                    # Add low/high error indices
                    if '_low' in field.lower():
                        contesto['error'][f'{coord_name}_low'] = {'index': i}
                    elif '_high' in field.lower():
                        contesto['error'][f'{coord_name}_high'] = {'index': i}
                    break

    return contesto

def _valida_etichette(etichette):
    import re

    # Regex patterns for validation
    key_pattern = r'^[a-zA-Z][a-zA-Z0-9_-]*$'
    value_pattern = r'^[a-zA-Z0-9_-]+$'

    errors = []

    # Validate each key-value pair
    for key, value in etichette.items():

        # Validate key type
        if not isinstance(key, str):
            errors.append({
                str(key): 'expected string or bytes-like object'
            })
            continue

        # Validate key format
        if not re.match(key_pattern, key):
            errors.append({
                key: f"Label key '{key}' does not match the regex {key_pattern}"
            })

        # Validate value type
        if not isinstance(value, str):
            errors.append({
                str(value): 'expected string or bytes-like object'
            })
            continue

        # Validate value format
        if not re.match(value_pattern, value):
            errors.append({
                value: f"Label value '{value}' does not match the regex {value_pattern}"
            })

    # If any errors occurred, raise ValidationError
    if errors:
        raise ValidationError(errors)

def ottieni_mappa_percorsi_logici(inventario, versione):
    mappa_percorsi = {}

    # Itera su tutte le versioni fino a quella specificata
    for v in range(versione + 1):
        if v in inventario:
            # Per ogni file nella versione
            for file_info in inventario[v]:
                percorso_logico = file_info['percorso_logico']
                file_contenuto = file_info['file_contenuto']

                # Aggiungi o aggiorna il set di file per questo percorso logico
                if percorso_logico not in mappa_percorsi:
                    mappa_percorsi[percorso_logico] = set()
                mappa_percorsi[percorso_logico].add(file_contenuto)

    return mappa_percorsi

