    """
    Converte il testo che di default è 'w:st="' in 'w-st="'.
    """
    return contesto.replace('w:st="', 'w-st="')

def _estrai_numero_e_supplmento_da_elemento_issue(issue):
    """
    Estrai i possibili valori di numero e supplemento dai issue.
    """
    numero = None
    supplemento = None

    # Check if issue is not None
    if issue:
        # Split issue by spaces to handle potential supplemento
        parts = issue.strip().split()

        # Get first part as numero
        if parts:
            try:
                numero = int(parts[0])
            except ValueError:
                numero = None

        # Check for supplemento in remaining parts
        if len(parts) > 1:
            supplemento = ' '.join(parts[1:])

    return numero, supplemento

def assorbimento(self, argomenti):
    # Create a copy of input list to avoid modifying original
    result = argomenti.copy()
    modified = True

    # Keep iterating while changes are being made
    while modified:
        modified = False

        # Compare each pair of expressions
        for i in range(len(result)):
            for j in range(len(result)):
                if i != j:
                    expr1 = result[i]
                    expr2 = result[j]

                    # Check for absorption law cases
                    # A & (A | B) = A
                    if expr1.is_and() and expr2.is_or():
                        if expr1 in expr2.operands:
                            result[i] = expr1
                            modified = True

                    # A | (A & B) = A         
                    elif expr1.is_or() and expr2.is_and():
                        if expr1 in expr2.operands:
                            result[i] = expr1
                            modified = True

                    # Check for negative absorption cases
                    # A & (~A | B) = A & B
                    if expr1.is_and() and expr2.is_or():
                        if expr1.negate() in expr2.operands:
                            result[i] = expr1 & expr2.operands[1]
                            modified = True

                    # A | (~A & B) = A | B
                    elif expr1.is_or() and expr2.is_and():
                        if expr1.negate() in expr2.operands:
                            result[i] = expr1 | expr2.operands[1]
                            modified = True

    # Remove duplicates and return
    return list(set(result))

def configurazione_base(utente, etcd_host="localhost", etcd_porta=2379):
    """
    Crea una configurazione con alcuni parametri semplici, che hanno un valore predefinito che può essere impostato.

    Argomenti:
    utente (str): il nome dell'utente per l'autenticazione statica.
    etcd_host (str): l'host per il database.
    etcd_porta (int): la porta per il database.

    Ritorna:
    dict: la configurazione creata.
    """
    config = {
        "autenticazione": {
            "tipo": "statica",
            "utente": utente
        },
        "database": {
            "tipo": "etcd",
            "host": etcd_host,
            "porta": etcd_porta
        }
    }

    return config

def estrai_versioni():
    """
    Ottieni le informazioni sulla versione o restituisci il valore predefinito se non è possibile ottenerle.
    """
    try:
        # Dizionario per memorizzare le versioni
        versioni = {}

        # Leggi la versione da un file di configurazione
        with open('version.txt', 'r') as f:
            for line in f:
                key, value = line.strip().split('=')
                versioni[key.strip()] = value.strip()

        return versioni

    except (FileNotFoundError, IOError, ValueError):
        # Restituisci valori predefiniti in caso di errore
        return {
            'major': '1',
            'minor': '0',
            'patch': '0'
        }

def piu_o_punto(pezzi):
    """
    Restituisci un "+" se non è già presente, altrimenti restituisci un "."
    """
    if "+" not in pezzi:
        return "+"
    else:
        return "."

def valida_gerarchia(self, oggetti_validati=True, controlla_digests=True, mostra_warning=False):
    """
    Valida la gerarchia di archiviazione.

    Restituisce:
        numero_oggetti - numero di oggetti verificati
        object_validi - numero di oggetti verificati che sono risultati validi
    """
    numero_oggetti = 0
    object_validi = 0

    try:
        # Scansiona ricorsivamente la gerarchia
        for root, dirs, files in os.walk(self.path):
            for file in files:
                numero_oggetti += 1
                file_path = os.path.join(root, file)

                # Controlla validità oggetto
                if oggetti_validati:
                    try:
                        with open(file_path, 'rb') as f:
                            content = f.read()

                        # Controlla digest se richiesto
                        if controlla_digests:
                            digest = hashlib.sha256(content).hexdigest()
                            digest_file = file_path + '.digest'

                            if os.path.exists(digest_file):
                                with open(digest_file) as f:
                                    stored_digest = f.read().strip()
                                if digest == stored_digest:
                                    object_validi += 1
                            elif mostra_warning:
                                print(f"Warning: digest file non trovato per {file_path}")
                        else:
                            object_validi += 1

                    except Exception as e:
                        if mostra_warning:
                            print(f"Warning: errore validazione {file_path}: {str(e)}")
                else:
                    object_validi += 1

    except Exception as e:
        if mostra_warning:
            print(f"Errore durante la scansione: {str(e)}")

    return numero_oggetti, object_validi

def _sostituisci_registro(parametri_flusso, numero_registro, valore_registro):
    """
    Sostituisci il valore dai flussi con il numero di registro specificato.

    La chiave `valore_registro` nel dizionario verrà sostituita dal numero di registro specificato da `numero_registro`.

    :param parametri_flusso: Dizionario contenente i flussi definiti  
    :param numero_registro: Il numero del registro in cui il valore verrà memorizzato  
    :param valore_registro: Chiave da sostituire con il numero di registro  
    """
    # Verifica se il valore_registro è presente nel dizionario
    if valore_registro in parametri_flusso:
        # Sostituisce il valore con il numero di registro
        parametri_flusso[valore_registro] = numero_registro

    # Controlla anche i valori annidati nel dizionario
    for chiave, valore in parametri_flusso.items():
        if isinstance(valore, dict):
            _sostituisci_registro(valore, numero_registro, valore_registro)
        elif isinstance(valore, list):
            for i, elemento in enumerate(valore):
                if isinstance(elemento, dict):
                    _sostituisci_registro(elemento, numero_registro, valore_registro)
                elif elemento == valore_registro:
                    valore[i] = numero_registro

def esegui_comando(comando, argomenti, cwd=None, verboso=False, nascondi_stderr=False, env=None):
    """
    Esegui il/i comando/i fornito/i.
    """
    import subprocess
    import sys

    # Prepara il comando completo
    if isinstance(comando, str):
        cmd = [comando]
    else:
        cmd = list(comando)

    # Aggiungi gli argomenti
    if argomenti:
        if isinstance(argomenti, str):
            cmd.append(argomenti)
        else:
            cmd.extend(argomenti)

    # Imposta stderr
    stderr = subprocess.DEVNULL if nascondi_stderr else subprocess.PIPE

    try:
        # Esegui il comando
        if verboso:
            print(f"Esecuzione comando: {' '.join(cmd)}")

        processo = subprocess.Popen(
            cmd,
            stdout=subprocess.PIPE,
            stderr=stderr,
            cwd=cwd,
            env=env,
            universal_newlines=True
        )

        # Ottieni output
        output, error = processo.communicate()

        # Gestisci errori
        if processo.returncode != 0 and not nascondi_stderr:
            if error:
                print(f"Errore: {error}", file=sys.stderr)
            return False

        if verboso and output:
            print(output)

        return True

    except Exception as e:
        if not nascondi_stderr:
            print(f"Errore nell'esecuzione del comando: {e}", file=sys.stderr)
        return False

def carica_configurazioni(file_configurazioni, sovrascrivi=None, risolvi_env=True):
    """
    Dato un elenco di nomi di file di configurazione, carica e valida ciascun file di configurazione.
    Restituisci i risultati come una tupla composta da:
    - un dizionario che associa il nome del file di configurazione alla corrispondente configurazione analizzata,
    - una sequenza di istanze di `logging.LogRecord` contenenti eventuali errori di analisi.
    """
    import yaml
    import os
    import logging
    from pathlib import Path

    configurazioni = {}
    errori = []
    logger = logging.getLogger(__name__)

    # Assicurati che file_configurazioni sia una lista
    if isinstance(file_configurazioni, (str, Path)):
        file_configurazioni = [file_configurazioni]

    for file_path in file_configurazioni:
        try:
            with open(file_path, 'r') as f:
                config = yaml.safe_load(f)

            # Risolvi variabili d'ambiente se richiesto
            if risolvi_env:
                config = _risolvi_variabili_ambiente(config)

            # Applica sovrascritture se presenti
            if sovrascrivi:
                config = _applica_sovrascritture(config, sovrascrivi)

            configurazioni[str(file_path)] = config

        except Exception as e:
            record = logger.makeLogRecord({
                'msg': f"Errore nel caricamento del file {file_path}: {str(e)}",
                'levelno': logging.ERROR,
                'exc_info': True
            })
            errori.append(record)

    return configurazioni, errori

def _risolvi_variabili_ambiente(config):
    """Helper function per risolvere le variabili d'ambiente nel config"""
    if isinstance(config, dict):
        return {k: _risolvi_variabili_ambiente(v) for k, v in config.items()}
    elif isinstance(config, list):
        return [_risolvi_variabili_ambiente(v) for v in config]
    elif isinstance(config, str) and config.startswith('${') and config.endswith('}'):
        env_var = config[2:-1]
        return os.environ.get(env_var, config)
    return config

def _applica_sovrascritture(config, sovrascrivi):
    """Helper function per applicare le sovrascritture al config"""
    if isinstance(sovrascrivi, dict):
        for k, v in sovrascrivi.items():
            if k in config and isinstance(config[k], dict) and isinstance(v, dict):
                config[k] = _applica_sovrascritture(config[k], v)
            else:
                config[k] = v
    return config

def verifcaOggetto(iface, candidato, tentativo=False):
    from zope.interface import Invalid
    from zope.interface.verify import verifyObject
    from zope.interface.exceptions import MultipleInvalid

    errori = []

    # Verifica che il candidato dichiari di fornire l'interfaccia
    if not tentativo:
        if not iface.providedBy(candidato):
            errori.append(Invalid(f"L'oggetto non dichiara di fornire l'interfaccia {iface.__name__}"))

    # Verifica i metodi richiesti
    for nome, desc in iface.namesAndDescriptions(1):
        if hasattr(desc, 'getSignatureInfo'): # è un metodo
            if not hasattr(candidato, nome):
                errori.append(Invalid(f"Il metodo richiesto '{nome}' non è presente"))
            else:
                metodo = getattr(candidato, nome)
                if not callable(metodo):
                    errori.append(Invalid(f"'{nome}' deve essere un metodo chiamabile"))
                else:
                    # Verifica la firma del metodo
                    try:
                        verifyObject(desc, metodo, tentativo)
                    except Invalid as e:
                        errori.append(e)
        else: # è un attributo
            if not hasattr(candidato, nome):
                errori.append(Invalid(f"L'attributo richiesto '{nome}' non è presente"))

    # Gestione degli errori
    if len(errori) > 1:
        raise MultipleInvalid(errori)
    elif len(errori) == 1:
        raise errori[0]

    return True

def valida_deprecazione_argomenti(self, argomenti_linea_comando, dizionario_argomenti):
    """
    Valida e stampa gli argomenti deprecati.

    :param argomenti_linea_comando: il dizionario degli argomenti dalla CLI
    :param dizionario_argomenti: il dizionario degli argomenti dai file
    """
    # Lista degli argomenti deprecati da controllare
    argomenti_deprecati = {
        'old_arg1': 'new_arg1',
        'old_arg2': 'new_arg2',
        'old_arg3': 'new_arg3'
    }

    # Controlla gli argomenti dalla linea di comando
    for arg_vecchio, arg_nuovo in argomenti_deprecati.items():
        if arg_vecchio in argomenti_linea_comando:
            print(f"ATTENZIONE: L'argomento '{arg_vecchio}' è deprecato. "
                  f"Utilizzare '{arg_nuovo}' al suo posto.")

    # Controlla gli argomenti dal dizionario
    if dizionario_argomenti:
        for arg_vecchio, arg_nuovo in argomenti_deprecati.items():
            if arg_vecchio in dizionario_argomenti:
                print(f"ATTENZIONE: L'argomento '{arg_vecchio}' nel file di configurazione è deprecato. "
                      f"Utilizzare '{arg_nuovo}' al suo posto.")
